import{_ as o,o as e,c as r,ak as a}from"./chunks/framework.CzRcPwtJ.js";const u=JSON.parse('{"title":"故事数据「不可整理项」网络研究结论（2026-06-17）","description":"","frontmatter":{},"headers":[],"relativePath":"../data/processed/story/RESEARCH_NOTES.md","filePath":"../data/processed/story/RESEARCH_NOTES.md","lastUpdated":1784443077000}'),l={name:"../data/processed/story/RESEARCH_NOTES.md"};function n(s,t,i,d,c,h){return e(),r("div",null,[...t[0]||(t[0]=[a('<h1 id="故事数据「不可整理项」网络研究结论-2026-06-17" tabindex="-1">故事数据「不可整理项」网络研究结论（2026-06-17） <a class="header-anchor" href="#故事数据「不可整理项」网络研究结论-2026-06-17" aria-label="Permalink to &quot;故事数据「不可整理项」网络研究结论（2026-06-17）&quot;">​</a></h1><blockquote><p>守密人裁定:对判定「不做」的整理项,通过搜索玩家 wiki / 社区信息尝试完成。 本档记录研究结论,<strong>防止未来会话重复劳动</strong>。研究用 anysearch + 社区 wiki(GameKee / 灰机wiki / Gamerch / 巴哈姆特),未爬取受 ToS 保护内容(灰机wiki 直接抓取返回 403)。</p></blockquote><hr><h2 id="结论速览-三项均经社区数据印证为「不可机器整理」-非主观回避" tabindex="-1">结论速览:三项均经社区数据印证为「不可机器整理」,非主观回避 <a class="header-anchor" href="#结论速览-三项均经社区数据印证为「不可机器整理」-非主观回避" aria-label="Permalink to &quot;结论速览:三项均经社区数据印证为「不可机器整理」,非主观回避&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项</th><th>原判定</th><th>网络研究结论</th><th>依据</th></tr></thead><tbody><tr><td>lore 868 条按<strong>类型</strong>分类(items/events=0)</td><td>不做(无客观信号)</td><td><strong>确认不可</strong></td><td>社区(LDPlayer/谷达鸭全地图收集)按<strong>章节/关卡</strong>组织收藏馆,不按类型分;类型分类无任何社区来源</td></tr><tr><td>potency(命轮) → 角色</td><td>不做(无外键)</td><td><strong>确认非真实关系</strong></td><td>灰机wiki:「命轮本身并没有界域使用限制」——命轮是<strong>通用可装备道具</strong>,不绑定角色</td></tr><tr><td>语音行 → 说话者</td><td>不可能(无字段)</td><td><strong>确认不可</strong></td><td>社区(nekolog/Gamerch)只有「角色↔声优(CV)」表(characters.json 已有 voice_actor),<strong>无逐句台词→说话者归属</strong></td></tr></tbody></table><h2 id="详细" tabindex="-1">详细 <a class="header-anchor" href="#详细" aria-label="Permalink to &quot;详细&quot;">​</a></h2><h3 id="_1-lore-类型分类" tabindex="-1">1. lore 类型分类 <a class="header-anchor" href="#_1-lore-类型分类" aria-label="Permalink to &quot;1. lore 类型分类&quot;">​</a></h3><ul><li>868 条 uncategorized 中,613 条为纯文本 flavor、210 条无正文,仅约 48 条有 <code>&lt;Title:&gt;</code> 头标记。</li><li>内部名表交叉:命中命轮名仅 1、命中道具名 139(均为「放逐/眷顾」类<strong>短词同形</strong>,正文实为台词,非道具)——不可据此判类。</li><li>社区收藏馆攻略(如「第一章全地图收集」「第二章全地图收集」)按 <code>章-关</code> 编号组织条目,<strong>与游戏内收藏馆的章节解锁一致</strong>。</li><li><strong>故</strong>:类型分类(人物/地点/造物/概念/道具/事件)非社区组织维度,无来源可借;而<strong>章节维度</strong>银芯已在 <code>story_units.json</code> / <code>lore_by_unit.json</code> 建好(184 条挂载)。</li></ul><h3 id="_2-potency-→-角色" tabindex="-1">2. potency → 角色 <a class="header-anchor" href="#_2-potency-→-角色" aria-label="Permalink to &quot;2. potency → 角色&quot;">​</a></h3><ul><li>命轮为通用装备,任意唤醒体可装备(仅有界域加强特性,非绑定)。</li><li><code>AwakerPotency.lua</code> 按技能/词条 id 索引,与角色无外键——与「命轮通用」的设定一致。</li><li><strong>故</strong>:此关系不存在,无需也无法建立。</li></ul><h3 id="_3-语音-→-说话者" tabindex="-1">3. 语音 → 说话者 <a class="header-anchor" href="#_3-语音-→-说话者" aria-label="Permalink to &quot;3. 语音 → 说话者&quot;">​</a></h3><ul><li><code>Voice.lua</code> 无说话者字段(见 lessons #37);128 个角色名锚点全是「闲话·关于X」的<strong>议论对象</strong>,非说话者。</li><li>社区仅提供「角色↔声优」对照,无「第 N 条语音是谁说的」逐句归属。</li><li><strong>故</strong>:逐句归属需运行时 hook(字节码常量表),非文本/社区可得。</li></ul><hr><h2 id="研究副产物-可供未来-lore-深化的线索-非本次落库" tabindex="-1">研究副产物:可供未来 lore 深化的线索(非本次落库) <a class="header-anchor" href="#研究副产物-可供未来-lore-深化的线索-非本次落库" aria-label="Permalink to &quot;研究副产物:可供未来 lore 深化的线索(非本次落库)&quot;">​</a></h2><ul><li><strong>角色克苏鲁原型考据</strong>(巴哈姆特《来分析一下忘却前夜的克苏鲁神话要素》):拉蒙娜=犹格·索托斯化身(乌姆尔·亚特·塔维尔)、萝坦=利维坦/乌加里特海怪 Lotan、塔薇与拉蒙娜剧情关联等。可作未来「角色↔神话原型」关联层的素材(需逐角色核实,本次不臆断落库)。</li><li><strong>角色界域/稀有度/Tier</strong>(Gamerch 全角色表):characters.json 现缺 realm/rarity 字段,社区有多源可校验数据,属可选未来 enrichment(非故事整理范畴)。</li></ul><blockquote><p>研究方法与结论可复现;若未来客户端版本更新,章节挂载与角色分类需重新核对。</p></blockquote>',16)])])}const _=o(l,[["render",n]]);export{u as __pageData,_ as default};
